oxy_webhelp_navlinks = {"tocId-d30753e28428":{"topics":[{"title":"IBM Db2","shortdesc":"<p class=\"shortdesc\">With IBM Db2 workloads, you can automate complex tasks such as database discovery and         data protection for managing databases.<\/p>","href":"db2\/ibm_db2.html","attributes":{"data-id":"ibm_db2"},"menu":{"hasChildren":false},"tocID":"ibm_db2-d30753e28429","next":"ibm_db2-d30753e28429"},{"title":"IBM Informix","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides native data protection and recovery for IBM Informix         instances.<\/p>","href":"informix\/ibm_informix.html","attributes":{"data-id":"ibm_informix"},"menu":{"hasChildren":false},"tocID":"ibm_informix-d30753e29436","next":"ibm_informix-d30753e29436"},{"title":"Microsoft SQL Server databases","shortdesc":"<p class=\"shortdesc\">A Rubrik cluster provides data management and protection for Microsoft SQL Server         databases.<\/p>","href":"common\/sql_server_databases.html","attributes":{"data-id":"sql_server_databases"},"menu":{"hasChildren":false},"tocID":"sql_server_databases-d30753e29737","next":"sql_server_databases-d30753e29737"},{"title":"MongoDB workloads","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Rubrik Security Cloud<\/span> protects your MongoDB sources, databases, and collections,         ensuring optimal storage efficiency and smooth database operations with its advanced         security features and strong data protection.<\/p>","href":"mongodb\/mongodb_workloads.html","attributes":{"data-id":"mongodb_workloads"},"menu":{"hasChildren":false},"tocID":"mongodb_workloads-d30753e30461","next":"mongodb_workloads-d30753e30461"},{"title":"MySQL","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> protects the MySQL databases from accidental deletions,         ransomware attacks, and other potential threats.<\/p>","href":"mysql\/mysql.html","attributes":{"data-id":"mysql"},"menu":{"hasChildren":false},"tocID":"mysql-d30753e31027","next":"mysql-d30753e31027"},{"title":"Oracle databases","shortdesc":"<p class=\"shortdesc\">You can use <span class=\"ph\">RSC<\/span> to back up, archive, replicate, and recover Oracle         databases.<\/p>","href":"oracle\/oracle_databases_rsc.html","attributes":{"data-id":"oracle_databases_rsc"},"menu":{"hasChildren":false},"tocID":"oracle_databases_rsc-d30753e31699","next":"oracle_databases_rsc-d30753e31699"},{"title":"PostgreSQL","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Rubrik Security Cloud<\/span> protects your PostgreSQL cluster by simplifying complex         backup and recovery processes, discovering the databases automatically, and protecting data         using SLA Domains.<\/p>","href":"postgresql\/postgresql.html","attributes":{"data-id":"postgresql"},"menu":{"hasChildren":false},"tocID":"postgresql-d30753e33253","next":"postgresql-d30753e33253"},{"title":"SAP HANA databases","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> enables administrators to implement backup policies on SAP HANA         databases running on public clouds and on-premises.<\/p>","href":"saas\/sap_hana_protection.html","attributes":{"data-id":"sap_hana_protection"},"menu":{"hasChildren":false},"tocID":"sap_hana_protection-d30753e33932","next":"sap_hana_protection-d30753e33932"}]}};